using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// Build the IChatClient through MEAI
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Create tool instances
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd(
    "ResearchAgent/1.0 (compatible; research-bot)");

var webSearch = new WebSearchTool(httpClient);
var notebook = new NoteTakingTool();

// Register tools via AIFunctionFactory
var tools = new AITool[]
{
    AIFunctionFactory.Create(
        webSearch.SearchWebAsync,
        "SearchWeb",
        "Searches the web for a query and returns a list of result titles, URLs, and snippets."),
    AIFunctionFactory.Create(
        webSearch.FetchPageContentAsync,
        "FetchPageContent",
        "Fetches the text content of a web page given its URL. Returns the first ~4000 characters."),
    AIFunctionFactory.Create(
        notebook.AddNote,
        "AddNote",
        "Saves a research note with a title and content to the notebook."),
    AIFunctionFactory.Create(
        notebook.GetAllNotes,
        "GetAllNotes",
        "Returns all saved research notes from the notebook."),
};

const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic provided by
    the user and produce a well-organized summary of your findings.

    Follow this workflow:
    1. Break the topic into 2-3 key search queries.
    2. Use the SearchWeb tool for each query to find relevant sources.
    3. Use FetchPageContent to read the most promising pages (up to 3-4 pages).
    4. Use AddNote to record key facts, statistics, and insights as you go.
    5. Once you have gathered enough information, use GetAllNotes to review your notes.
    6. Write a final, well-structured summary with sections and source attributions.

    Guidelines:
    - Be thorough but concise — aim for a summary that is informative and readable.
    - Always cite your sources with URLs.
    - If a page fetch fails, move on to the next source.
    - Do not fabricate information; only report what you find.
    """;

// Build the agent
var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "An AI agent that researches topics using web search and note-taking tools.",
    tools: tools);

// Get the research topic
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");
Console.WriteLine(new string('─', 60));

// Create a session and run the agent
var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions);

Console.WriteLine(response.Text);
Console.WriteLine(new string('─', 60));

if (response.Usage is { } usage)
{
    Console.WriteLine(
        $"\n📊 Tokens — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}, " +
        $"Total: {usage.TotalTokenCount}");
}

Console.WriteLine($"📝 Notes taken: {notebook.Count}");
Console.WriteLine("✅ Research complete.");

