using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search and page-fetching capabilities for the research agent.
/// Uses DuckDuckGo HTML search (no API key required).
/// </summary>
public sealed partial class WebSearchTool(HttpClient httpClient)
{
    private const int MaxContentLength = 4000;

    /// <summary>
    /// Searches the web and returns a list of results with titles, URLs, and snippets.
    /// </summary>
    [Description("Searches the web for a query and returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web.")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept", "text/html");

            using var response = await httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    /// <summary>
    /// Fetches the text content of a web page.
    /// </summary>
    [Description("Fetches the text content of a web page given its URL.")]
    public async Task<string> FetchPageContentAsync(
        [Description("The full URL of the web page to fetch.")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri) ||
                (uri.Scheme != "http" && uri.Scheme != "https"))
            {
                return "Invalid URL. Please provide a valid http or https URL.";
            }

            using var request = new HttpRequestMessage(HttpMethod.Get, uri);
            request.Headers.Add("Accept", "text/html");

            using var response = await httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = ExtractTextFromHtml(html);

            return text.Length > MaxContentLength
                ? text[..MaxContentLength] + "\n\n[Content truncated]"
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string ParseSearchResults(string html)
    {
        var results = new StringBuilder();
        var matches = SearchResultPattern().Matches(html);

        if (matches.Count == 0)
        {
            return "No search results found.";
        }

        var count = 0;
        foreach (Match match in matches)
        {
            if (count >= 8) break;

            var rawUrl = WebUtility.HtmlDecode(match.Groups["url"].Value);
            var title = StripHtmlTags(WebUtility.HtmlDecode(match.Groups["title"].Value)).Trim();
            var snippet = StripHtmlTags(WebUtility.HtmlDecode(match.Groups["snippet"].Value)).Trim();

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var actualUrl = ExtractRedirectUrl(rawUrl) ?? rawUrl;

            if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(actualUrl))
                continue;

            results.AppendLine($"[{count + 1}] {title}");
            results.AppendLine($"    URL: {actualUrl}");
            if (!string.IsNullOrWhiteSpace(snippet))
                results.AppendLine($"    {snippet}");
            results.AppendLine();

            count++;
        }

        return count > 0
            ? results.ToString()
            : "No search results could be parsed.";
    }

    private static string? ExtractRedirectUrl(string url)
    {
        // DuckDuckGo uses //duckduckgo.com/l/?uddg=<encoded_url>&...
        if (!url.Contains("uddg="))
            return null;

        var match = UddgPattern().Match(url);
        return match.Success ? Uri.UnescapeDataString(match.Groups[1].Value) : null;
    }

